public void visit(NodeTraversal t, Node n, Node parent) {
    if (t.inGlobalScope()) {
        return;
    }

    // Record if the return statement is non-empty
    if (n.isReturn() && n.getFirstChild() != null) {
        data.get(t.getScopeRoot()).recordNonEmptyReturn();
    }

    // Early exit for the first-order function analyzer
    if (t.getScopeDepth() <= 2) {
        return;
    }

    // Handle variable assignments and escapes
    if (n.isName() && NodeUtil.isLValue(n) &&
        // Avoid handling bleeding functions that create variables in inner scopes
        !NodeUtil.isBleedingFunctionName(n)) {
        String name = n.getString();
        Scope scope = t.getScope();
        Var var = scope.getVar(name);
        if (var != null) {
            Scope ownerScope = var.getScope();
            if (ownerScope.isLocal()) {
                data.get(ownerScope.getRootNode()).recordAssignedName(name);
            }

            // Check for escaped variables
            if (scope != ownerScope && ownerScope.isLocal()) {
                data.get(ownerScope.getRootNode()).recordEscapedVarName(name);
            }
        }
    } else if (n.isGetProp() && n.isUnscopedQualifiedName() &&
        NodeUtil.isLValue(n)) {
        String name = NodeUtil.getRootOfQualifiedName(n).getString();
        Scope scope = t.getScope();
        Var var = scope.getVar(name);
        if (var != null) {
            Scope ownerScope = var.getScope();
            // Check for escaped qualified names
            if (scope != ownerScope && ownerScope.isLocal()) {
                data.get(ownerScope.getRootNode())
                    .recordEscapedQualifiedName(n.getQualifiedName());
            }
        }
    }
}
